parameters.query:
SELECT COALESCE(
  (
    SELECT summary
    FROM bot_memory_summaries
    WHERE chat_id = '{{$json.chatId}}'
    ORDER BY updated_at DESC
    LIMIT 1
  ),
  ''
) AS summary;

