const allowedGroups = [
  '120363400682390076@g.us'
];

const data = $json.body?.data || {};
const key = data.key || {};
const msg = data.message || {};

const chatId = String(key.remoteJid || '').trim();

if (!allowedGroups.includes(chatId)) {
  return [];
}

if (key.fromMe === true) {
  return [];
}

const text = String(
  msg.conversation ||
  msg.extendedTextMessage?.text ||
  msg.imageMessage?.caption ||
  msg.documentMessage?.caption ||
  ''
).trim();

const lower = text.toLowerCase();

const isAlikhan =
  lower === 'алихан' ||
  lower.startsWith('алихан ') ||
  lower.includes('алихан');

if (!isAlikhan) {
  return [];
}

return [
  {
    json: {
      ...$json,
      userText: text,
      userMessage: text,
      chatId,
      number: chatId,
      fromMe: false,
      sender: data.pushName || 'Unknown',
      messageId: key.id || '',
      messageTimestamp: data.messageTimestamp || null,
    },
  },
];

const data = $json.body?.data || {};
const msg = data.message || {};
const contextInfo = data.contextInfo || {};

const text = String(
  msg.conversation ||
  msg.extendedTextMessage?.text ||
  msg.imageMessage?.caption ||
  msg.documentMessage?.caption ||
  ''
).trim();

const lower = text.toLowerCase();

const quotedDoc =
  contextInfo.quotedMessage?.documentMessage ||
  contextInfo.quotedMessage?.documentWithCaptionMessage?.message?.documentMessage ||
  contextInfo.quotedMessage?.documentWithCaptionMessage?.documentMessage ||
  null;

function parseDateRu(s) {
  const m1 = s.match(/(\d{2})\.(\d{2})\.(\d{4})/);
  if (m1) return `${m1[3]}-${m1[2]}-${m1[1]}`;

  const m2 = s.match(/(\d{4})-(\d{2})-(\d{2})/);
  if (m2) return `${m2[1]}-${m2[2]}-${m2[3]}`;

  return null;
}

function todayIso() {
  return new Date().toISOString().slice(0, 10);
}

function shiftDate(days) {
  const d = new Date();
  d.setDate(d.getDate() + days);
  return d.toISOString().slice(0, 10);
}

function pad2(n) {
  return String(n).padStart(2, '0');
}

const MONTHS_RU = {
  'январь': 1,
  'января': 1,
  'февраль': 2,
  'февраля': 2,
  'март': 3,
  'марта': 3,
  'апрель': 4,
  'апреля': 4,
  'май': 5,
  'мая': 5,
  'июнь': 6,
  'июня': 6,
  'июль': 7,
  'июля': 7,
  'август': 8,
  'августа': 8,
  'сентябрь': 9,
  'сентября': 9,
  'октябрь': 10,
  'октября': 10,
  'ноябрь': 11,
  'ноября': 11,
  'декабрь': 12,
  'декабря': 12
};

function parseMonthRangeRu(s) {
  const m = s.match(
    /(январь|января|февраль|февраля|март|марта|апрель|апреля|май|мая|июнь|июня|июль|июля|август|августа|сентябрь|сентября|октябрь|октября|ноябрь|ноября|декабрь|декабря)\s+(\d{4})/i
  );

  if (!m) return null;

  const monthName = m[1].toLowerCase();
  const year = Number(m[2]);
  const month = MONTHS_RU[monthName];

  if (!month || !year) return null;

  const start = `${year}-${pad2(month)}-01`;
  const lastDay = new Date(year, month, 0).getDate();
  const end = `${year}-${pad2(month)}-${pad2(lastDay)}`;

  return { start, end };
}

const idMatch =
  lower.match(/\bid\s*(\d+)\b/i) ||
  lower.match(/\bид\s*(\d+)\b/i);

const lookupId = idMatch ? idMatch[1] : '';

const docCompareIds = Array.from(
  text.matchAll(/\b(?:id|ид)\s*(\d+)\b/gi),
  (m) => m[1]
);

function firstMatchId(patterns) {
  for (const pattern of patterns) {
    const m = lower.match(pattern);
    if (m) return m[1];
  }
  return '';
}

const explicitOldId = firstMatchId([
  /стар(?:ый|ая|ое|ую|ой)?(?:\s+\S+){0,6}?\s+(?:id|ид)\s*(\d+)/i,
  /(?:id|ид)\s*(\d+)(?:\s+\S+){0,6}?\s+стар(?:ый|ая|ое|ую|ой)?/i,
  /пер(?:вый|вая|вое)(?:\s+\S+){0,6}?\s+(?:id|ид)\s*(\d+)/i,
]);

const explicitNewId = firstMatchId([
  /нов(?:ый|ая|ое|ую|ой)?(?:\s+\S+){0,6}?\s+(?:id|ид)\s*(\d+)/i,
  /(?:id|ид)\s*(\d+)(?:\s+\S+){0,6}?\s+нов(?:ый|ая|ое|ую|ой)?/i,
  /втор(?:ой|ая|ое|ую)(?:\s+\S+){0,6}?\s+(?:id|ид)\s*(\d+)/i,
]);

const hasDocumentCompareIntent =
  lower.includes('сравни документ') ||
  lower.includes('сравнить документ') ||
  lower.includes('сравни регламент') ||
  lower.includes('сравнить регламент') ||
  lower.includes('что изменилось между') ||
  lower.includes('найди отличия') ||
  lower.includes('найти отличия') ||
  lower.includes('отличия между') ||
  lower.includes('что появилось нового') ||
  lower.includes('нового в новой версии') ||
  (
    lower.includes('первый') &&
    lower.includes('стар') &&
    lower.includes('втор') &&
    lower.includes('нов')
  );

const hasRegulationFactQuestionIntent =
  lower.includes('можно ли') ||
  lower.includes('разрешено ли') ||
  lower.includes('запрещено ли') ||
  lower.includes('нельзя ли') ||
  lower.includes('какой штраф') ||
  lower.includes('штраф') ||
  lower.includes('по регламенту') ||
  lower.includes('согласно регламенту') ||
  lower.includes('пункт') ||
  lower.includes('раздел') ||
  lower.includes('шашлык') ||
  lower.includes('мангал') ||
  lower.includes('костер') ||
  lower.includes('костёр') ||
  lower.includes('барашек') ||
  lower.includes('барашка') ||
  lower.includes('бараш') ||
  lower.includes('баран') ||
  lower.includes('обряд') ||
  lower.includes('обычай') ||
  lower.includes('зарезать') ||
  lower.includes('кровь') ||
  lower.includes('пролить') ||
  lower.includes('отход') ||
  lower.includes('мусор') ||
  lower.includes('пожарн') ||
  lower.includes('санитар') ||
  lower.includes('оос') ||
  lower.includes('окружающей среды');

const docCompareOldId = explicitOldId || docCompareIds[0] || '';
const docCompareNewId =
  explicitNewId ||
  docCompareIds.find((id) => id !== docCompareOldId) ||
  docCompareIds[1] ||
  '';

let command = 'ai';
let summaryStartDate = '';
let summaryEndDate = '';
let calendarRange = 'all';

if (lower === 'алихан') {
  command = 'only_name';

} else if (lower.includes('статус памяти')) {
  command = 'memory_status';

} else if (
  lookupId &&
  (
    lower.includes('удали событие') ||
    lower.includes('удалить событие') ||
    lower.includes('отмени событие') ||
    lower.includes('отменить событие')
  )
) {
  command = 'calendar_delete';

} else if (
  docCompareIds.length >= 2 &&
  hasDocumentCompareIntent
) {
  command = 'document_compare';

} else if (
  lower.includes('какой сегодня день') ||
  lower.includes('какая сегодня дата') ||
  lower.includes('дата сегодня') ||
  lower.includes('сегодняшняя дата') ||
  lower.includes('какое сегодня число') ||
  lower.includes('какой день календаря') ||
  lower.includes('день календаря') ||
  lower.includes('сколько времени') ||
  lower.includes('который час') ||
  lower.includes('время сейчас') ||
  lower.includes('текущее время')
) {
  command = 'current_datetime';

} else if (hasRegulationFactQuestionIntent) {
  command = 'fact_lookup';

} else if (
  lookupId &&
  (
    lower.includes('id') ||
    lower.includes('ид') ||
    lower.includes('покажи') ||
    lower.includes('найди') ||
    lower.includes('подними')
  )
) {
  command = 'id_lookup';

} else if (
  lower.includes('добавь событие') ||
  lower.includes('создай событие') ||
  lower.includes('запланируй') ||
  lower.includes('поставь в календарь') ||
  lower.includes('добавь в календарь') ||
  lower.includes('состоится') ||
  (
    (lower.includes('напомни') || lower.includes('напомнить')) &&
    (
      lower.includes('совещание') ||
      lower.includes('встреч') ||
      lower.includes('планерк') ||
      lower.includes('планёрк') ||
      lower.includes('событие') ||
      lower.includes('звонок')
    )
  )
) {
  command = 'calendar_create';

} else if (
  lower.includes('что сегодня') ||
  lower.includes('события на сегодня') ||
  lower.includes('календарь на сегодня')
) {
  command = 'calendar_list';
  calendarRange = 'today';

} else if (
  lower.includes('что завтра') ||
  lower.includes('события на завтра') ||
  lower.includes('календарь на завтра')
) {
  command = 'calendar_list';
  calendarRange = 'tomorrow';

} else if (
  lower.includes('календарь на неделю') ||
  lower.includes('события на неделю') ||
  lower.includes('что на неделю')
) {
  command = 'calendar_list';
  calendarRange = 'week';

} else if (
  lower.includes('какие события') ||
  lower.includes('что в календаре') ||
  lower.includes('что запланировано') ||
  lower.includes('события добавлены')
) {
  command = 'calendar_list';
  calendarRange = 'all';

} else if (
  lower.includes('кто чаще всего писал') ||
  lower.includes('активность участников') ||
  lower.includes('кто выкладывал фото') ||
  lower.includes('кто выкладывал документы') ||
  lower.includes('кто отправлял фото') ||
  lower.includes('кто отправлял документы')
) {
  command = 'participant_activity';

} else if (
  lower.includes('участники') ||
  lower.includes('кто в группе') ||
  lower.includes('люди в группе')
) {
  command = 'group_participants';

} else if (
  lower.includes('сводка') ||
  lower.includes('самари') ||
  lower.includes('итоги')
) {
  command = 'period_summary';

  summaryStartDate = todayIso();
  summaryEndDate = todayIso();

  if (lower.includes('вчера')) {
    summaryStartDate = shiftDate(-1);
    summaryEndDate = shiftDate(-1);

  } else if (lower.includes('сегодня')) {
    summaryStartDate = todayIso();
    summaryEndDate = todayIso();

  } else {
    const monthRange = parseMonthRangeRu(lower);

    if (monthRange) {
      summaryStartDate = monthRange.start;
      summaryEndDate = monthRange.end;

    } else {
      const range = lower.match(
        /с\s+(\d{2}\.\d{2}\.\d{4}|\d{4}-\d{2}-\d{2})\s+по\s+(\d{2}\.\d{2}\.\d{4}|\d{4}-\d{2}-\d{2})/
      );

      if (range) {
        summaryStartDate = parseDateRu(range[1]) || summaryStartDate;
        summaryEndDate = parseDateRu(range[2]) || summaryEndDate;
      } else {
        const singleDate = parseDateRu(lower);
        if (singleDate) {
          summaryStartDate = singleDate;
          summaryEndDate = singleDate;
        }
      }
    }
  }

} else if (
  quotedDoc &&
  (
    lower.includes('документ') ||
    lower.includes('содержание') ||
    lower.includes('кратко') ||
    lower.includes('что в')
  )
) {
  command = 'quoted_document_summary';

} else if (
  lower.includes('подними') ||
  lower.includes('найди') ||
  lower.includes('покажи') ||
  lower.includes('подробнее') ||
  lower.includes('расскажи подробнее') ||
  lower.includes('когда это было') ||
  lower.includes('конкретные фото') ||
  lower.includes('переписку')
) {
  command = 'fact_lookup';

} else if (lower.includes('кто ты') || lower.includes('ты кто')) {
  command = 'who_are_you';
}

const cleanedUserMessage = text.replace(/^алихан\s*/i, '').trim();
const current_datetime = new Date().toISOString();

return [
  {
    json: {
      ...$json,
      command,
      userMessage: cleanedUserMessage || text,
      number: String(data.key?.remoteJid || '').trim(),
      chatId: String(data.key?.remoteJid || '').trim(),
      fromMe: data.key?.fromMe === true,

      quotedDocumentMessageId: contextInfo.stanzaId || '',
      quotedDocumentFileName: quotedDoc?.fileName || quotedDoc?.title || '',
      quotedDocumentMimeType: quotedDoc?.mimetype || '',

      summaryStartDate,
      summaryEndDate,

      calendarRange,
      lookupId,
      docCompareOldId,
      docCompareNewId,
      docCompareIds,

      current_datetime,
    },
  },
];

const allowedGroups = [
  '120363400682390076@g.us'
];

const data = $json.body?.data || {};
const key = data.key || {};
const msg = data.message || {};

const chatId = String(key.remoteJid || '').trim();

if (!allowedGroups.includes(chatId)) {
  return [];
}

if (key.fromMe === true) {
  return [];
}

const messageType = String(data.messageType || '').toLowerCase();

const imageMessage =
  msg.imageMessage ||
  msg.viewOnceMessage?.message?.imageMessage ||
  msg.viewOnceMessageV2?.message?.imageMessage ||
  msg.ephemeralMessage?.message?.imageMessage ||
  null;

const isImage =
  messageType.includes('image') ||
  !!imageMessage;

if (!isImage) {
  return [];
}

const img = imageMessage || {};

return [
  {
    json: {
      ...$json,
      chatId,
      number: chatId,
      fromMe: false,
      sender: data.pushName || 'Unknown',
      messageId: key.id || '',
      messageTimestamp: data.messageTimestamp || null,
      messageType: data.messageType || '',
      caption: img.caption || '',
      mimetype: img.mimetype || 'image/jpeg',
      fileName: `${key.id || 'photo'}.jpeg`,
    },
  },
];

