const raw = String($json.choices?.[0]?.message?.content || '').trim();

let cleaned = raw
  .replace(/^```json/i, '')
  .replace(/^```/i, '')
  .replace(/```$/i, '')
  .trim();

let event;

try {
  event = JSON.parse(cleaned);
} catch (e) {
  return [
    {
      json: {
        ok: false,
        error: 'Не смог разобрать JSON события',
