  const MAX_CHARS_PER_DOC = 80000;

  function cleanText(value) {
    return String(value || '')
      .replace(/\u0000/g, ' ')
      .replace(/\r/g, '\n')
      .replace(/\n{3,}/g, '\n\n')
      .trim();
  }

  function truncateDoc(value) {
    const text = cleanText(value);

    if (text.length <= MAX_CHARS_PER_DOC) {
      return {
        text,
        truncated: false,
        originalLength: text.length,
      };
    }

    return {
      text: text.slice(0, MAX_CHARS_PER_DOC),
      truncated: true,
      originalLength: text.length,
    };
  }

  let status = 'ok';
  let errorText = '';

  if (!foundOld && !foundNew) {
    status = 'missing';
