  } else if (!foundOld) {
    status = 'missing';
    errorText = `Старый документ ID ${oldId} не найден.`;
  } else if (!foundNew) {
    status = 'missing';
    errorText = `Новый документ ID ${newId} не найден.`;
  }

  const oldDoc = truncateDoc(row.old_content);
  const newDoc = truncateDoc(row.new_content);

  const truncated = oldDoc.truncated || newDoc.truncated;

