function splitByPageMarkers(text) {
  const source = String(text || '');
  const markerPattern = /(?:^|\n)\s*---\s*(vision\s+)?page\s+(\d{1,4})\s*---\s*(?=\n|$)/gi;
  const markers = [];
  let match;

  while ((match = markerPattern.exec(source)) !== null) {
    markers.push({
      markerStart: match.index,
      markerEnd: markerPattern.lastIndex,
      pageNumber: Number(match[2]),
      isVision: Boolean(match[1]),
    });
  }

  const pageMap = new Map();
  for (let index = 0; index < markers.length; index += 1) {
    const current = markers[index];
    const next = markers[index + 1];
    const pageText = source.slice(current.markerEnd, next ? next.markerStart : source.length).trim();
    pageMap.set(current.pageNumber, pageText);
  }

  return pageMap;
}

function getPages(pageMap, pagesArray) {
  const foundPages = [];
  const missingPages = [];
  const parts = [];

  for (const page of pagesArray || []) {
    if (pageMap.has(page)) {
      foundPages.push(page);
      parts.push(`--- page ${page} ---\n${pageMap.get(page)}`);
    } else {
      missingPages.push(page);
    }
  }

  return {
    text: parts.join('\n\n').trim(),
    foundPages,
    missingPages,
  };
}

function hasClassicPageMarkers(text) {
  return /(?:^|\n)\s*---\s*page\s+\d{1,4}\s*---\s*(?=\n|$)/i.test(String(text || ''));
}

function hasVisionPageMarkers(text) {
  return /(?:^|\n)\s*---\s*vision\s+page\s+\d{1,4}\s*---\s*(?=\n|$)/i.test(String(text || ''));
}

function escapeRegExp(value) {
  return String(value).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function titleTermPattern(term) {
  return escapeRegExp(term.replace(/ё/gi, 'е').toLowerCase()).replace(/\s+/g, '\\s+');
}

function buildHeadingPatterns(section) {
  const titleAlternation = section.titleTerms.map(titleTermPattern).join('|');
  const number = section.number;
  const markdownPrefix = String.raw`\s*(?:#{1,6}\s*)?(?:\*\*)?\s*`;
  const markdownSuffix = String.raw`\s*(?:\*\*)?\s*`;

  return [
    new RegExp(
      `(?:^|\\n)${markdownPrefix}(?:раздел\\s*)?${number}\\s*(?:[.)\\-–—:]|\\s)\\s*(?:\\*\\*)?\\s*(?:${titleAlternation})[^\\n]{0,220}${markdownSuffix}`,
      'i'
    ),
    new RegExp(
      `(?:^|\\n)${markdownPrefix}(?:${titleAlternation})${markdownSuffix}(?:\\n|$)`,
      'i'
    ),
  ];
}

function isTocLikeLine(line) {
  const value = String(line || '').trim();
  if (!value) return false;

  return (
    /\.{3,}\s*\d{1,4}\s*$/.test(value) ||
    /\s{3,}\d{1,4}\s*$/.test(value) ||
    /…+\s*\d{1,4}\s*$/.test(value)
  );
}

function isSummaryLikeLine(line) {
  const value = String(line || '')
    .replace(/[ё]/gi, 'е')
    .toLowerCase()
    .trim();

  return (
    value.includes('краткое описание смысла страницы') ||
    value.includes('краткое описание страницы') ||
    value.includes('описание смысла страницы') ||
    value.includes('summary') ||
    value.includes('page summary')
  );
}

function lineAt(originalText, index) {
  const start = originalText.lastIndexOf('\n', Math.max(0, index - 1)) + 1;
  const endIndex = originalText.indexOf('\n', index);
  const end = endIndex >= 0 ? endIndex : originalText.length;
  return originalText.slice(start, end);
}

function detectBodyStart(originalText, searchText) {
  const contentMarkers = [];
  const contentPattern = /(?:^|\n)\s*с\s*о\s*д\s*е\s*р\s*ж\s*а\s*н\s*и\s*е\s*(?:\n|$)/gi;
  let contentMatch;
  while ((contentMatch = contentPattern.exec(searchText)) !== null) {
    contentMarkers.push(contentMatch.index);
  }

  const firstSectionPatterns = [
    /(?:^|\n)\s*(?:#{1,6}\s*)?(?:\*\*)?\s*(?:раздел\s*)?1\s*(?:[.)\-–—:]|\s)\s*(?:\*\*)?\s*(?:термины|терминология|сокращения|обозначения|определения)[^\n]{0,220}(?:\*\*)?\s*/gi,
    /(?:^|\n)\s*(?:#{1,6}\s*)?(?:\*\*)?\s*(?:термины|терминология|сокращения|обозначения|определения)(?:\*\*)?\s*(?:\n|$)/gi,
  ];

  const candidates = [];
  for (const pattern of firstSectionPatterns) {
    let match;
    while ((match = pattern.exec(searchText)) !== null) {
      const start = match.index + (match[0].startsWith('\n') ? 1 : 0);
      const line = lineAt(originalText, start);
      if (!isTocLikeLine(line) && !isSummaryLikeLine(line)) {
        candidates.push(start);
      }
    }
  }

  if (!candidates.length) {
    return 0;
  }

  candidates.sort((a, b) => a - b);

  if (!contentMarkers.length) {
    return candidates[0];
  }

  const lastContentMarker = Math.max(...contentMarkers);
  const afterContent = candidates.find((index) => index > lastContentMarker + 20);
  return afterContent ?? candidates[candidates.length - 1];
}

function findHeadingStart(originalText, searchText, section, bodyStart) {
  const bodySearchText = searchText.slice(bodyStart);
  const patterns = buildHeadingPatterns(section);
  for (const pattern of patterns) {
    const match = bodySearchText.match(pattern);
    if (match && typeof match.index === 'number') {
      const absoluteIndex = bodyStart + match.index + (match[0].startsWith('\n') ? 1 : 0);
      const line = lineAt(originalText, absoluteIndex);
      if (!isTocLikeLine(line) && !isSummaryLikeLine(line)) {
        return absoluteIndex;
      }
    }
  }
  return -1;
}

function collectStarts(originalText, searchText, bodyStart) {
  const starts = sections.map((section) => {
    const start = findHeadingStart(originalText, searchText, section, bodyStart);
    return {
      ...section,
      start,
      matchedBy: start >= 0 ? 'exact_heading' : 'not_found',
    };
  });

  return starts.map((entry) => {
    if (entry.start < 0) return { ...entry, end: -1 };
    const laterStarts = starts
      .filter((other) => other.start > entry.start)
      .map((other) => other.start)
      .sort((a, b) => a - b);
    return { ...entry, end: laterStarts[0] || originalText.length };
  });
}

function sliceSection(originalText, startInfo) {
  if (startInfo.start < 0 || startInfo.end <= startInfo.start) return '';
  return originalText.slice(startInfo.start, startInfo.end).trim();
}

function findKeywordIndexes(searchText, section) {
  return section.keywords
    .map((keyword) => searchText.indexOf(keyword.replace(/ё/gi, 'е').toLowerCase()))
    .filter((index) => index >= 0)
    .sort((a, b) => a - b);
}

function makeSnippet(originalText, searchText, section) {
  const indexes = findKeywordIndexes(searchText, section).filter((index) => {
    const line = lineAt(originalText, index);
    return !isTocLikeLine(line) && !isSummaryLikeLine(line);
  });

  if (!indexes.length) return '';

  const parts = [];
  const seen = new Set();
  for (const index of indexes.slice(0, 3)) {
    const start = Math.max(0, index - 2500);
    const end = Math.min(originalText.length, index + 8000);
    const key = `${start}:${end}`;
    if (!seen.has(key)) {
      parts.push(originalText.slice(start, end).trim());
      seen.add(key);
    }
  }
  return parts.join('\n\n--- related fragment ---\n\n').trim();
}

function buildKnownPageMapChunks() {
  const oldPageMap = splitByPageMarkers(oldContent);
  const newPageMap = splitByPageMarkers(newContent);

  return sections.map((section) => {
    const pageConfig = knownPageMap4014To4013[section.key] || { oldPages: [], newPages: [] };
    const oldPages = pageConfig.oldPages || [];
    const newPages = pageConfig.newPages || [];
    const oldPageResult = getPages(oldPageMap, oldPages);
    const newPageResult = getPages(newPageMap, newPages);
    const oldFound = oldPages.length > 0 && oldPageResult.foundPages.length > 0;
    const newFound = newPages.length > 0 && newPageResult.foundPages.length > 0;
    const oldRelatedText = oldFound ? '' : makeSnippet(oldContent, oldSearch, section);
    const newRelatedText = newFound ? '' : makeSnippet(newContent, newSearch, section);
    const oldChunkMethod = oldFound ? 'known_page_map' : (oldRelatedText ? 'related_fragment' : 'not_found');
    const newChunkMethod = newFound ? 'known_page_map' : (newRelatedText ? 'related_fragment' : 'not_found');
    const sectionMappingNote = sectionMappingNotes4014To4013[section.key] || '';

    const oldSectionStatus = oldFound
      ? `В старом документе раздел выделен по страницам ${oldPageResult.foundPages.join(', ')}.`
      : oldRelatedText
        ? 'В старом документе отдельный раздел не выделен, передан только related fragment при наличии. Не считай его отдельным разделом старой версии.'
        : 'В старом документе отдельный раздел и related fragment не найдены.';

    const newSectionStatus = newFound
      ? `В новом документе раздел выделен по страницам ${newPageResult.foundPages.join(', ')}.`
      : newRelatedText
        ? 'В новом документе отдельный раздел не выделен, передан только related fragment при наличии. Не считай его отдельным разделом новой версии.'
        : 'В новом документе отдельный раздел и related fragment не найдены.';

    return {
      json: {
        status: 'ok',
        shouldCallXai: true,
        isDocumentCompareChunk: true,
        number: $('Router Алихан').item.json.number,
        old_id: oldId,
        new_id: newId,
        old_file_name: oldFileName,
        new_file_name: newFileName,
        sectionKey: section.key,
        sectionTitle: section.title,
        chunkMethod: 'known_page_map',
        oldChunkMethod,
        newChunkMethod,
        oldPages,
        newPages,
        oldFoundPages: oldPageResult.foundPages,
        newFoundPages: newPageResult.foundPages,
        oldMissingPages: oldPageResult.missingPages,
        newMissingPages: newPageResult.missingPages,
        sectionMappingNote,
        oldText: oldPageResult.text,
        newText: newPageResult.text,
        oldRelatedText,
        newRelatedText,
        oldFound,
        newFound,
        oldIsExactSection: oldFound,
        newIsExactSection: newFound,
        oldIsRelatedFragment: !oldFound && Boolean(oldRelatedText),
        newIsRelatedFragment: !newFound && Boolean(newRelatedText),
        oldBodyStart: -1,
        newBodyStart: -1,
        oldHeadingStart: -1,
        newHeadingStart: -1,
        oldHeadingLine: '',
        newHeadingLine: '',
        headingLine: '',
        oldMatchedBy: oldChunkMethod,
        newMatchedBy: newChunkMethod,
        chunkInstruction: [
          `Старый документ: ID ${oldId}, файл ${oldFileName}`,
          `Новый документ: ID ${newId}, файл ${newFileName}`,
          `Раздел: ${section.title}`,
          'Раздел выделен по известной карте страниц для пары 4014 → 4013.',
          'Это не универсальное правило для всех документов.',
          sectionMappingNote ? `Смысловое соответствие разделов: ${sectionMappingNote}.` : 'Смысловое соответствие разделов: номера разделов могут отличаться между версиями.',
          'Старый раздел 6 “Отчётность” соответствует новому разделу 8.',
          'Старый раздел 7 “Ответственность” соответствует новому разделу 9.',
          'Старый раздел 8 “Штрафы” соответствует новому разделу 10.',
          'Старый раздел 9 “Согласование” соответствует новому разделу 11.',
          'Старый раздел 10 “Приложения” соответствует новому разделу 12.',
          'Не считай раздел удалённым только потому, что его номер изменился.',
          oldSectionStatus,
          newSectionStatus,
          `oldPages: ${JSON.stringify(oldPages)}`,
          `newPages: ${JSON.stringify(newPages)}`,
          `oldMissingPages: ${JSON.stringify(oldPageResult.missingPages)}`,
          `newMissingPages: ${JSON.stringify(newPageResult.missingPages)}`,
          '',
          'Сравни только этот раздел. Не делай выводы по другим разделам.',
          'Не фантазируй. Если подтверждения нет в переданном тексте, так и напиши.',
          'Если oldPages/newPages заданы и соответствующие oldMissingPages/newMissingPages пустые, считай релевантные страницы переданными в анализ.',
          'Не пиши “не подтверждено” только потому, что раздел найден по карте страниц, а не по regex-заголовку.',
