          '',
          'НОВЫЙ РАЗДЕЛ ПО СТРАНИЦАМ:',
          newPageResult.text || '[отдельный раздел по карте страниц не выделен в новом документе]',
          '',
          'НОВЫЙ СВЯЗАННЫЙ ФРАГМЕНТ:',
          newRelatedText || '[связанный фрагмент не найден или не нужен]',
        ].join('\n'),
      },
    };
  });
}

function buildHeadingSectionChunks() {
  const oldBodyStart = detectBodyStart(oldContent, oldSearch);
  const newBodyStart = detectBodyStart(newContent, newSearch);
  const oldStarts = collectStarts(oldContent, oldSearch, oldBodyStart);
  const newStarts = collectStarts(newContent, newSearch, newBodyStart);

  return sections.map((section) => {
    const oldInfo = oldStarts.find((item) => item.key === section.key);
    const newInfo = newStarts.find((item) => item.key === section.key);

    const oldExactText = sliceSection(oldContent, oldInfo);
    const newExactText = sliceSection(newContent, newInfo);
    const oldHeadingLine = Number.isFinite(oldInfo?.start) && oldInfo.start >= 0 ? lineAt(oldContent, oldInfo.start).trim() : '';
    const newHeadingLine = Number.isFinite(newInfo?.start) && newInfo.start >= 0 ? lineAt(newContent, newInfo.start).trim() : '';
    const oldRelatedText = oldExactText ? '' : makeSnippet(oldContent, oldSearch, section);
    const newRelatedText = newExactText ? '' : makeSnippet(newContent, newSearch, section);

    const oldIsExactSection = Boolean(oldExactText);
    const newIsExactSection = Boolean(newExactText);
    const oldIsRelatedFragment = !oldIsExactSection && Boolean(oldRelatedText);
    const newIsRelatedFragment = !newIsExactSection && Boolean(newRelatedText);
    const oldText = oldExactText || oldRelatedText;
    const newText = newExactText || newRelatedText;
    const oldChunkMethod = oldIsExactSection ? 'heading_section' : (oldIsRelatedFragment ? 'related_fragment' : 'not_found');
    const newChunkMethod = newIsExactSection ? 'heading_section' : (newIsRelatedFragment ? 'related_fragment' : 'not_found');

    const oldSectionStatus = oldIsExactSection
      ? 'В старом документе найден точный раздел.'
      : oldIsRelatedFragment
        ? 'В старом документе точный раздел не найден; найден только связанный фрагмент. Не считай его отдельным разделом старой версии.'
        : 'В старом документе точный раздел и связанный фрагмент не найдены.';

    const newSectionStatus = newIsExactSection
      ? 'В новом документе найден точный раздел.'
      : newIsRelatedFragment
        ? 'В новом документе точный раздел не найден; найден только связанный фрагмент. Не считай его отдельным разделом новой версии.'
        : 'В новом документе точный раздел и связанный фрагмент не найдены.';

    return {
      json: {
        status: 'ok',
        shouldCallXai: true,
        isDocumentCompareChunk: true,
        number: $('Router Алихан').item.json.number,
        old_id: oldId,
        new_id: newId,
        old_file_name: oldFileName,
        new_file_name: newFileName,
        sectionKey: section.key,
        sectionTitle: section.title,
        chunkMethod: oldIsExactSection || newIsExactSection ? 'heading_section' : (oldIsRelatedFragment || newIsRelatedFragment ? 'related_fragment' : 'not_found'),
        oldChunkMethod,
        newChunkMethod,
        oldPages: [],
        newPages: [],
        oldFoundPages: [],
        newFoundPages: [],
        oldMissingPages: [],
        newMissingPages: [],
        sectionMappingNote: '',
        oldText,
        newText,
        oldFound: oldIsExactSection,
        newFound: newIsExactSection,
        oldRelatedText,
        newRelatedText,
        oldIsExactSection,
        newIsExactSection,
        oldIsRelatedFragment,
        newIsRelatedFragment,
        oldBodyStart,
        newBodyStart,
        oldHeadingStart: oldInfo?.start ?? -1,
        newHeadingStart: newInfo?.start ?? -1,
        oldHeadingLine,
        newHeadingLine,
        headingLine: newHeadingLine || oldHeadingLine,
        oldMatchedBy: oldInfo?.matchedBy || 'not_found',
        newMatchedBy: newInfo?.matchedBy || 'not_found',
        chunkInstruction: [
          `Старый документ: ID ${oldId}, файл ${oldFileName}`,
          `Новый документ: ID ${newId}, файл ${newFileName}`,
          `Раздел: ${section.title}`,
          oldSectionStatus,
          newSectionStatus,
          '',
          'Сравни только этот раздел. Не делай выводы по другим разделам.',
          'Не фантазируй. Если подтверждения нет в переданном тексте, так и напиши.',
          'Считай раздел найденным только если найден точный заголовок раздела.',
          'Связанный фрагмент по ключевым словам — это только контекст, не доказательство наличия раздела.',
          'Если точный раздел есть только в новом документе, укажи: "новый раздел".',
          'Если точный раздел есть только в старом документе, укажи: "не найдено в новой версии".',
          'Верни строгий markdown с полями:',
          '- sectionTitle',
          '- keyChanges',
          '- added',
          '- changed',
          '- removedOrNotFound',
          '- risksForProject',
          '- actions',
          '',
          'СТАРЫЙ ТОЧНЫЙ РАЗДЕЛ:',
          oldExactText || '[точный раздел не найден в старом документе]',
          '',
          'СТАРЫЙ СВЯЗАННЫЙ ФРАГМЕНТ:',
          oldRelatedText || '[связанный фрагмент не найден или не нужен]',
          '',
          'НОВЫЙ ТОЧНЫЙ РАЗДЕЛ:',
          newExactText || '[точный раздел не найден в новом документе]',
          '',
          'НОВЫЙ СВЯЗАННЫЙ ФРАГМЕНТ:',
          newRelatedText || '[связанный фрагмент не найден или не нужен]',
        ].join('\n'),
      },
    };
  });
}

const useKnownPageMap =
  oldId === '4014' &&
  newId === '4013' &&
  hasClassicPageMarkers(oldContent) &&
  hasVisionPageMarkers(newContent);

return useKnownPageMap ? buildKnownPageMapChunks() : buildHeadingSectionChunks();

function readNodeItems(name) {
  try {
    return $items(name).map((item) => item.json);
  } catch (e) {
    return [];
  }
}

const chunks = readNodeItems('Build Document Compare Chunks');
const inputResults = $input.all().map((item) => item.json);
const xaiResults = inputResults.length ? inputResults : readNodeItems('xAI Compare Document Chunk');
const firstChunk = chunks[0] || {};

if (firstChunk.status === 'missing' || firstChunk.shouldCallXai === false) {
  return [
    {
      json: {
        status: 'missing',
        shouldCallXai: false,
        isDocumentCompareAggregate: false,
        number: firstChunk.number,
        text: firstChunk.errorText || firstChunk.text || 'Не удалось подготовить сравнение документов.',
        errorText: firstChunk.errorText || firstChunk.text || 'Не удалось подготовить сравнение документов.',
        old_id: firstChunk.old_id,
        new_id: firstChunk.new_id,
        old_file_name: firstChunk.old_file_name,
        new_file_name: firstChunk.new_file_name,
      },
    },
  ];
}

const resultsByIndex = xaiResults.map((result) => {
  return String(result.choices?.[0]?.message?.content || result.result || '').trim();
});

const aggregatedSections = chunks.map((chunk, index) => {
  const result = resultsByIndex[index] || 'xAI не вернул результат по этому разделу.';
  return [
    `## ${chunk.sectionTitle}`,
    `sectionKey: ${chunk.sectionKey}`,
    `chunkMethod: ${chunk.chunkMethod || 'unknown'}`,
    `oldChunkMethod: ${chunk.oldChunkMethod || 'unknown'}`,
    `newChunkMethod: ${chunk.newChunkMethod || 'unknown'}`,
    `sectionMappingNote: ${chunk.sectionMappingNote || ''}`,
    `oldFound: ${chunk.oldFound}`,
    `newFound: ${chunk.newFound}`,
    `oldPages: ${JSON.stringify(chunk.oldPages || [])}`,
    `newPages: ${JSON.stringify(chunk.newPages || [])}`,
    `oldMissingPages: ${JSON.stringify(chunk.oldMissingPages || [])}`,
    `newMissingPages: ${JSON.stringify(chunk.newMissingPages || [])}`,
    `oldIsExactSection: ${chunk.oldIsExactSection}`,
    `newIsExactSection: ${chunk.newIsExactSection}`,
    `oldIsRelatedFragment: ${chunk.oldIsRelatedFragment}`,
    `newIsRelatedFragment: ${chunk.newIsRelatedFragment}`,
    '',
    result,
  ].join('\n');
});

const aggregatedChunkResults = aggregatedSections.join('\n\n---\n\n');

const finalSummaryPrompt = [
  `Старый документ: ID ${firstChunk.old_id}, файл ${firstChunk.old_file_name}`,
  `Новый документ: ID ${firstChunk.new_id}, файл ${firstChunk.new_file_name}`,
  '',
  'Ниже результаты сравнения документов по разделам. Составь финальный отчёт только на основании этих результатов.',
  'Не выдумывай. Не добавляй выводы, которых нет в результатах по разделам.',
  '',
  'Критически важно по статусам:',
  '- Для chunkMethod=known_page_map oldFound/newFound означают, что релевантные страницы раздела переданы по известной карте страниц.',
  '- Не считай раздел неподтверждённым только потому, что он найден по known_page_map, а не по regex-заголовку.',
  '- Если oldMissingPages/newMissingPages пустые, считай указанные oldPages/newPages переданными в анализ.',
  '- RelatedFragment — это только дополнительный контекст по ключевым словам, не доказательство существования отдельного раздела.',
  '- Если sectionMappingNote указывает old section X → new section Y, считай это перенумерацией/структурным переносом, а не удалением.',
  '- Если содержание найдено под другим номером раздела, пиши “перенумеровано” или “перенесено”, а не “удалено”.',
  '- Если страница содержит начало следующего раздела, учитывай только часть, относящуюся к текущему разделу.',
  '',
  'Особенно проверь, что учтены:',
  '- раздел 5 ООС: новая версия должна включать страницы 15–17, включая пункты 5.17–5.26;',
  '- блок “Вахтовый поселок (лагерь)”: новая версия должна учитывать страницу 15;',
  '- раздел согласования: старый раздел 9 соответствует новому разделу 11;',
  '- разделы нового документа 6–12: пожарная безопасность, санитарно-эпидемиологические требования, отчётность, ответственность, штрафы, согласование и приложения.',
  '',
  'Не пиши следующие выводы, если результаты по разделам показывают, что страницы переданы:',
  '- “пункты 5.17–5.26 отсутствуют”;',
  '- “вахтовый посёлок удалён”;',
  '- “пункты 9.1 и 9.2 удалены”.',
  '',
  'Формат финального отчёта:',
  '1) Краткий вывод',
  '2) Главное, что появилось нового',
  '3) Новые обязанности подрядчика',
  '4) Новые требования по ОТ/ПБ/РБ',
  '5) Новые требования по ООС',
  '6) Новые требования по пожарной безопасности',
  '7) Санитарно-эпидемиологические требования',
  '8) Изменения по отчётности',
  '9) Изменения по ответственности и штрафам',
  '10) Изменения по приложениям и формам',
  '11) Красные флаги / ошибки в тексте нового регламента',
  '12) Что нужно сделать проектной команде',
  '',
  'РЕЗУЛЬТАТЫ ПО РАЗДЕЛАМ:',
  aggregatedChunkResults,
].join('\n');

return [
  {
    json: {
      status: 'ok',
      shouldCallXai: true,
      isDocumentCompareAggregate: true,
      number: firstChunk.number,
      old_id: firstChunk.old_id,
      new_id: firstChunk.new_id,
      old_file_name: firstChunk.old_file_name,
      new_file_name: firstChunk.new_file_name,
      aggregatedChunkResults,
      finalSummaryPrompt,
    },
  },
];

const items = $input.all();

return items.map((item) => {
  const json = item.json || {};

  return {
    json: {
      ...json,
      number: String(json.number || $('Router Алихан').item.json.number || ''),
      text: String(
        json.text ||
        json.finalText ||
        json.answer ||
        json.choices?.[0]?.message?.content ||
        'Ошибка: текст ответа не сформирован.'
      ),
    },
  };
});

